module sr_latch (
    input wire invalid_S,
    input wire R,
    output reg Q,
    output reg Qn
);
    always @ (invalid_S or R) begin
        if (invalid_S && !R) begin
            Q <= 1'b1;
            Qn <= 1'b0;
        end else if (!invalid_S && R) begin
            Q <= 1'b0;
            Qn <= 1'b1;
        end else if (!invalid_S && !R) begin
            // Retain previous state
            Q <= Q;
            Qn <= Qn;
        end else begin
            // Invalid state when both invalid_S and R are high
            Q <= 1'bx;
            Qn <= 1'bx;
        end
    end
endmodule
